const allInputs = $input.all();

const yfInput = allInputs.find(i => 
  i.json.quoteResponse || 
  i.json.meta?.status === 200 ||
  Array.isArray(i.json.body)
) || allInputs[0];

const ethInput = allInputs.find(i => 
  i.json.body?.ethereum || 
  i.json.ethereum
) || allInputs[1];

const yfRaw = yfInput.json;
const quotes = yfRaw.quoteResponse?.result
             || yfRaw.body
             || (Array.isArray(yfRaw) ? yfRaw : []);
const yf = {};
quotes.forEach(q => {
  const sym = q.symbol || q.ticker || '';
  const price = q.regularMarketPrice?.raw ?? q.regularMarketPrice ?? 0;
  if (sym) yf[sym] = Number(price) || 0;
});

const usdsgd = yf['USDSGD=X'] || 1.35;
const phpsgd = yf['PHPSGD=X'] || 0.023;
const S = v => (v == null || isNaN(v) || !isFinite(v)) ? 0 : Number(v);

// ── Read ETH & PSE Prices from TradingView nodes ────────────────
let ethSGD = 0;
const tvPsePrices = {};

try {
  const tvEthData = $('TradingView ETHSGD').first().json;
  ethSGD = S(tvEthData.data?.[0]?.d?.[1]);
} catch (e) {
  // Fallback to CoinGecko input if TradingView fails
  const ethRaw = ethInput.json.body || ethInput.json;
  ethSGD = Number(ethRaw?.ethereum?.sgd) || Number(ethInput.json?.ethereum?.sgd) || Number(ethInput.json?.body?.ethereum?.sgd) || 0;
}

try {
  const tvPseData = $('TradingView PSE').first().json;
  (tvPseData.data || []).forEach(item => {
    const name = item.d[0];
    const close = item.d[1];
    tvPsePrices[name] = S(close);
  });
} catch (e) {
  // Handled via fallback values in the loop below
}

// ── SG + US Positions (C38U removed, names & costs matched to MooMoo console) ──
const pos = [
  {sym:'A17U.SI', n:'A17U',  qty:400,    cost:2.53,    c:'SGD'},
  {sym:'AJBU.SI', n:'AJBU',  qty:500,    cost:1.9562,  c:'SGD'}, // Name matched
  {sym:'BUOU.SI', n:'BUOU',  qty:1500,   cost:0.9398,  c:'SGD'}, // Cost updated
  {sym:'J69U.SI', n:'J69U',  qty:1000,   cost:2.1109,  c:'SGD'}, // Name matched, cost 2.1109
  {sym:'JYEU.SI', n:'JYEU',  qty:900,    cost:0.5898,  c:'SGD'},
  {sym:'ME8U.SI', n:'ME8U',  qty:200,    cost:1.93,    c:'SGD'},
  {sym:'NVDA',    n:'NVDA',  qty:3,      cost:173.73,  c:'USD'}, // Cost updated
  {sym:'O5RU.SI', n:'O5RU',  qty:500,    cost:1.2515,  c:'SGD'}, // Name matched, cost updated
  {sym:'TSLA',    n:'TSLA',  qty:0.3549, cost:318.683, c:'USD'}
];

let totVal = 0, totPL = 0;
const rows = [];

for (const p of pos) {
  const rawP = S(yf[p.sym]);
  const pr   = S(p.c === 'USD' ? rawP * usdsgd : rawP);
  const co   = S(p.c === 'USD' ? p.cost * usdsgd : p.cost);
  const val  = S(p.qty * pr);
  const cst  = S(p.qty * co);
  const pl   = S(val - cst);
  const pct  = cst > 0 ? S(pl / cst * 100) : 0;
  totVal += val; totPL += pl;
  rows.push({ n:p.n, price:rawP, currency:p.c, qty:p.qty, cost:p.cost, val, pl, pct, noP:!rawP });
}

// ── ETH (Blended cost and qty updated, row push corrected) ──────
const ethQty = 0.6338458;
const ethBlendedCost = 2526.13484;

const eV = S(ethQty * ethSGD);
const ePL = S(eV - ethQty * ethBlendedCost);
const ePct = S((ethSGD - ethBlendedCost) / ethBlendedCost * 100);

totVal += eV;
totPL  += ePL;

rows.push({ n:'ETH', price:ethSGD, currency:'SGD', qty:ethQty, cost:ethBlendedCost, val:eV, pl:ePL, pct:ePct, noP:false });

// ── DragonFi PERA+ Positions (Dynamic TV Prices & Fallback) ───
const peraFallback = {
  'AREIT': 38.40,
  'CREIT': 3.50,
  'MBT':   63.00,
  'MREIT': 14.00,
  'RCR':   6.75
};

const peraPos = [
  {n:'AREIT', qty:1200, cost:40.6445},
  {n:'CREIT', qty:8000, cost:3.4038},
  {n:'MBT',   qty:430,  cost:67.6711},
  {n:'MREIT', qty:1900, cost:13.5704},
  {n:'RCR',   qty:4300, cost:6.79}
];

let peraTotVal = 0, peraTotPL = 0;
const peraRows = [];

for (const p of peraPos) {
  const pricePhp = tvPsePrices[p.n] || peraFallback[p.n] || 0;
  const val      = S(p.qty * pricePhp);
  const cst      = S(p.qty * p.cost);
  const pl       = S(val - cst);
  const pct      = cst > 0 ? S(pl / cst * 100) : 0;
  peraTotVal += val;
  peraTotPL  += pl;
  peraRows.push({ n:p.n, sym:p.n + '.PS', price:pricePhp, qty:p.qty, cost:p.cost, val, pl, pct, noP:false });
}

// ── Alerts ─────────────────────────────────────────────────────
const alerts = [];
rows.forEach(r => {
  if (r.pct <= -10 && !r.noP && !r.stable) alerts.push(r.n + ' ' + r.pct.toFixed(1) + '%');
});
peraRows.forEach(r => {
  if (r.pct <= -10 && !r.noP) alerts.push('PERA+ ' + r.n + ' ' + r.pct.toFixed(1) + '%');
});

return [{ json: {
  rows,
  peraRows,
  total_value:    Math.round(totVal * 100) / 100,
  total_pl:       Math.round(totPL * 100) / 100,
  pera_total_val: Math.round(peraTotVal * 100) / 100,
  pera_total_pl:  Math.round(peraTotPL * 100) / 100,
  usdsgd,
  phpsgd,
  eth_sgd:        ethSGD,
  alerts,
  alert_count:    alerts.length,
  timestamp:      new Date().toISOString()
}}];

const calcPL = $('Calculate Dividends').first().json;
const rawResp = $input.first().json;

// ── Parse Claude response ──────────────────────────────────────
let ai;
try {
  const text = rawResp.choices[0].message.content;
  const clean = text.replace(/```json|```/g, '').trim();
  ai = JSON.parse(clean);
} catch(e) {
  ai = {
    overall_summary: 'Portfolio update complete. AI analysis unavailable this run.',
    detailed_analysis: '',
    watchlist: '',
    portfolio_status: calcPL.total_pl >= 0 ? 'UP' : 'DOWN',
    biggest_mover: { name: 'N/A', direction: 'UP', note: '' },
    positions: calcPL.rows.map(r => ({
      name: r.n, pct: r.pct,
      status: r.stable ? 'OK' : r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT',
      commentary: ''
    })),
    pera_positions: calcPL.peraRows.map(r => ({
      name: r.n, pct: r.pct,
      status: r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT',
      commentary: ''
    })),
    alerts: calcPL.alerts.length ? [{ level: 'YELLOW', title: 'Alerts', body: calcPL.alerts.join(', ') }] : [],
    recommendation: 'Review positions manually.',
    market_context: ''
  };
}

// ── Helpers ────────────────────────────────────────────────────
const ts = new Date(calcPL.timestamp).toLocaleString('en-SG', {
  timeZone: 'Asia/Singapore', weekday:'long', day:'2-digit',
  month:'short', year:'numeric', hour:'2-digit', minute:'2-digit'
});
const fmt    = v => (v >= 0 ? '+' : '') + 'S$' + Math.abs(Math.round(v)).toLocaleString();
const fmtPhp = v => (v >= 0 ? '+' : '-') + '₱' + Math.abs(Math.round(v)).toLocaleString();
const f1  = v => Number(v).toFixed(1);
const plColor    = v => v >= 0 ? '#00c896' : '#e74c3c';
const statusColor = s => ({ STRONG:'#00c896', OK:'#6db8a0', WATCH:'#f5a623', ALERT:'#e74c3c' }[s] || '#6db8a0');
const alertBg    = l => ({ RED:'rgba(231,76,60,0.12)', YELLOW:'rgba(245,166,35,0.10)', GREEN:'rgba(0,200,150,0.10)' }[l] || 'rgba(255,255,255,0.04)');
const alertBorder = l => ({ RED:'#e74c3c', YELLOW:'#f5a623', GREEN:'#00c896' }[l] || '#444');
const alertIcon  = l => ({ RED:'&#9940;', YELLOW:'&#9888;', GREEN:'&#9989;' }[l] || '&#8226;');

// ── MooMoo SG Position rows ────────────────────────────────────
const posRows = calcPL.rows.map(r => {
  const aiPos  = (ai.positions || []).find(p => p.name === r.n) || {};
  const status = r.stable ? 'OK' : r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT';
  const color  = statusColor(aiPos.status || status);
  const sign   = r.pct >= 0 ? '+' : '';
  const valStr = 'S$' + Math.round(r.val).toLocaleString();
  const plStr  = Math.abs(r.pl) < 1
    ? (r.pl >= 0 ? '+S$<1' : '-S$<1')
    : (r.pl >= 0 ? '+S$' : '-S$') + Math.abs(Math.round(r.pl)).toLocaleString();
  const plSGD  = r.pl >= 0 ? '#00c896' : '#e74c3c';
  return `<tr>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:#c8d8e8;padding:13px 12px">${r.n}</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:${color};padding:13px 8px">${sign}${r.pct.toFixed(1)}%</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:12px;color:${plSGD};padding:13px 8px">${plStr}</td>
    <td style="padding:13px 8px"><span style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.08em;padding:3px 9px;border-radius:20px;background:${color}22;color:${color};border:1px solid ${color}44">${aiPos.status || status}</span></td>
    <td style="font-size:11px;color:#6b8599;padding:13px 8px">${valStr}</td>
    <td style="font-size:12px;color:#7a9ab5;padding:13px 12px">${aiPos.commentary || ''}</td>
  </tr>`;
}).join('');

// ── DragonFi PERA+ rows ────────────────────────────────────────
const peraRows = calcPL.peraRows.map(r => {
  const aiPos  = (ai.pera_positions || []).find(p => p.name === r.n) || {};
  const status = r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT';
  const color  = statusColor(aiPos.status || status);
  const sign   = r.pct >= 0 ? '+' : '';
  const valStr = '₱' + Math.round(r.val).toLocaleString();
  const plStr  = Math.abs(r.pl) < 1
    ? (r.pl >= 0 ? '+₱<1' : '-₱<1')
    : (r.pl >= 0 ? '+₱' : '-₱') + Math.abs(Math.round(r.pl)).toLocaleString();
  const plColor2 = r.pl >= 0 ? '#00c896' : '#e74c3c';
  return `<tr>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:#c8d8e8;padding:13px 12px">${r.n}</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:${color};padding:13px 8px">${sign}${r.pct.toFixed(1)}%</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:12px;color:${plColor2};padding:13px 8px">${plStr}</td>
    <td style="padding:13px 8px"><span style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.08em;padding:3px 9px;border-radius:20px;background:${color}22;color:${color};border:1px solid ${color}44">${aiPos.status || status}</span></td>
    <td style="font-size:11px;color:#6b8599;padding:13px 8px">${valStr}</td>
    <td style="font-size:12px;color:#7a9ab5;padding:13px 12px">${aiPos.commentary || ''}</td>
  </tr>`;
}).join('');

// ── Alerts HTML ────────────────────────────────────────────────
const alertsHtml = (ai.alerts && ai.alerts.length > 0)
  ? ai.alerts.map(al => `<div style="display:flex;gap:14px;padding:15px 18px;border-radius:6px;margin-bottom:10px;background:${alertBg(al.level)};border-left:3px solid ${alertBorder(al.level)};align-items:flex-start">
      <span style="font-size:15px;flex-shrink:0;margin-top:1px">${alertIcon(al.level)}</span>
      <div><strong style="font-size:13px;color:#c8d8e8;display:block;margin-bottom:4px">${al.title}</strong><p style="font-size:12px;color:#6b8599;margin:0;line-height:1.5">${al.body}</p></div>
    </div>`).join('')
  : `<div style="display:flex;gap:14px;padding:15px 18px;border-radius:6px;background:rgba(0,200,150,0.08);border-left:3px solid #00c896;align-items:center">
      <span style="font-size:15px">&#9989;</span>
      <div><strong style="font-size:13px;color:#c8d8e8">All Clear</strong><p style="font-size:12px;color:#6b8599;margin:4px 0 0">No threshold alerts today.</p></div>
    </div>`;

// ── Status pill ────────────────────────────────────────────────
const pillColor = ai.portfolio_status === 'UP' ? '#00c896' : ai.portfolio_status === 'DOWN' ? '#e74c3c' : '#3d9be9';
const pillLabel = ai.portfolio_status === 'UP' ? '&#9650; UP' : ai.portfolio_status === 'DOWN' ? '&#9660; DOWN' : '&#8212; FLAT';
const statusPill = `<span style="font-family:'Space Mono',monospace;font-size:10px;font-weight:700;padding:3px 10px;border-radius:20px;background:${pillColor}22;color:${pillColor};border:1px solid ${pillColor}44;margin-left:10px">${pillLabel}</span>`;

const costBasis = calcPL.total_value - calcPL.total_pl;
const plPct     = costBasis > 0 ? (calcPL.total_pl / costBasis * 100).toFixed(1) : '0.0';
const peraPlPct = calcPL.pera_total_val > 0 ? ((calcPL.pera_total_pl / (calcPL.pera_total_val - calcPL.pera_total_pl)) * 100).toFixed(1) : '0.0';

// ── Dividends Section ──────────────────────────────────────────
const divRows = (calcPL.dividends || []).map(r => {
  const amtStr = r.currency === 'SGD' ? 'S$' + r.amount.toFixed(4) : '₱' + r.amount.toFixed(4);
  const exD = new Date(r.exDate);
  const payD = new Date(r.payDate);
  const today = new Date();

  // Calculate status and color
  let status = 'Paid';
  let color = '#6db8a0'; // Muted green

  // Normalize dates to midnight for accurate comparison
  const todayMidnight = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  const exMidnight = new Date(exD.getFullYear(), exD.getMonth(), exD.getDate());
  const payMidnight = new Date(payD.getFullYear(), payD.getMonth(), payD.getDate());

  if (todayMidnight < exMidnight) {
    status = 'Upcoming';
    color = '#3d9be9'; // Blue
  } else if (todayMidnight >= exMidnight && todayMidnight < payMidnight) {
    status = 'Pending Pay';
    color = '#f5a623'; // Orange
  }

  const statusHtml = `<span style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.08em;padding:3px 9px;border-radius:20px;background:${color}22;color:${color};border:1px solid ${color}44">${status}</span>`;

  const fmtDate = dateObj => dateObj.toLocaleDateString('en-SG', {
    day: '2-digit', month: 'short', year: 'numeric'
  });

  return `<tr>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:#c8d8e8;padding:13px 12px">${r.n}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#6b8599;padding:13px 8px">${fmtDate(exD)}</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:12px;color:#00c896;padding:13px 8px">${amtStr}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#6b8599;padding:13px 8px">${fmtDate(payD)}</td>
    <td style="padding:13px 8px">${statusHtml}</td>
  </tr>`;
}).join('');

const divTableHtml = `
<div style="margin-bottom:28px">
  <div class="section-label">📅 Dividends Calendar (Declared / Recent)</div>
  <div style="background:#111820;border:1px solid #1a2636;border-radius:8px;overflow:hidden">
    <table>
      <thead><tr>
        <th>Asset</th><th>Ex-Date</th><th>Amount</th><th>Payment Date</th><th>Status</th>
      </tr></thead>
      <tbody>${divRows}</tbody>
    </table>
  </div>
</div>
`;

// ── Full HTML ──────────────────────────────────────────────────
const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Bobby Portfolio &mdash; ${ts}</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet">
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{background:#0a0e14;color:#c8d8e8;font-family:'DM Sans',sans-serif;min-height:100vh}
body::before{content:'';position:fixed;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,0.025) 2px,rgba(0,0,0,0.025) 4px);pointer-events:none;z-index:0}
.wrap{max-width:980px;margin:0 auto;padding:36px 20px;position:relative;z-index:1}
table{width:100%;border-collapse:collapse}
thead th{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:0.13em;color:#3d5a72;text-transform:uppercase;padding:9px 12px;text-align:left;border-bottom:1px solid #1a2636}
tbody tr{border-bottom:1px solid rgba(26,38,54,0.6);transition:background 0.15s}
tbody tr:hover{background:#111c28}
.section-label{font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.15em;color:#3d5a72;text-transform:uppercase;margin-bottom:12px}
@media(max-width:600px){.hide-mobile{display:none}.stat-grid{grid-template-columns:1fr 1fr!important}.stat-val{font-size:20px!important}}
</style>
</head>
<body>
<div class="wrap">

<div style="display:flex;justify-content:space-between;align-items:flex-start;border-bottom:1px solid #1a2636;padding-bottom:24px;margin-bottom:32px;flex-wrap:wrap;gap:12px">
  <div>
    <div style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.18em;color:#3d5a72;text-transform:uppercase;margin-bottom:8px">&#128200; Daily Portfolio Report</div>
    <div style="font-family:'Space Mono',monospace;font-size:22px;font-weight:700;color:#c8d8e8;letter-spacing:0.04em">Bobby Dionido ${statusPill}</div>
  </div>
  <div style="text-align:right">
    <div style="font-family:'Space Mono',monospace;font-size:10px;color:#3d5a72;letter-spacing:0.1em">Generated ${ts}</div>
    <div style="font-family:'Space Mono',monospace;font-size:10px;color:#3d5a72;margin-top:5px">USD/SGD ${calcPL.usdsgd} &nbsp;|&nbsp; PHP/SGD ${calcPL.phpsgd.toFixed(4)} &nbsp;|&nbsp; ETH S$${Math.round(calcPL.eth_sgd).toLocaleString()}</div>
  </div>
</div>

<div class="stat-grid" style="display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-bottom:16px">
  <div style="background:#111820;border:1px solid #1a2636;border-radius:8px;padding:22px">
    <div style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.13em;color:#3d5a72;text-transform:uppercase;margin-bottom:10px">MooMoo SG Value</div>
    <div class="stat-val" style="font-family:'Space Mono',monospace;font-size:26px;font-weight:700;color:#3d9be9">S$${Math.round(calcPL.total_value).toLocaleString()}</div>
    <div style="font-size:11px;color:${plColor(calcPL.total_pl)};margin-top:5px;font-family:'Space Mono',monospace">${fmt(calcPL.total_pl)} &nbsp;(${plPct}%)</div>
  </div>
  <div style="background:#111820;border:1px solid #1a2636;border-radius:8px;padding:22px">
    <div style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.13em;color:#3d5a72;text-transform:uppercase;margin-bottom:10px">DragonFi PERA+</div>
    <div class="stat-val" style="font-family:'Space Mono',monospace;font-size:26px;font-weight:700;color:#3dcc9b">&#8369;${Math.round(calcPL.pera_total_val).toLocaleString()}</div>
    <div style="font-size:11px;color:${plColor(calcPL.pera_total_pl)};margin-top:5px;font-family:'Space Mono',monospace">${fmtPhp(calcPL.pera_total_pl)} &nbsp;(${peraPlPct}%)</div>
  </div>
  <div style="background:#111820;border:1px solid #1a2636;border-radius:8px;padding:22px">
    <div style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.13em;color:#3d5a72;text-transform:uppercase;margin-bottom:10px">Biggest Mover</div>
    <div class="stat-val" style="font-family:'Space Mono',monospace;font-size:22px;font-weight:700;color:${ai.biggest_mover?.direction==='UP'?'#00c896':'#e74c3c'}">${ai.biggest_mover?.name || 'N/A'}</div>
    <div style="font-size:11px;color:#3d5a72;margin-top:5px">${ai.biggest_mover?.note || ''}</div>
  </div>
</div>

<div style="background:#111820;border:1px solid #1a2636;border-radius:8px;padding:24px;margin-bottom:20px">
  <div class="section-label">AI Analysis</div>
  <p style="font-size:14px;line-height:1.75;color:#c8d8e8">${ai.overall_summary}</p>
  ${ai.detailed_analysis ? `<p style="margin-top:14px;font-size:13px;line-height:1.8;color:#a0b8cc">${ai.detailed_analysis}</p>` : ''}
  ${ai.market_context ? `<p style="margin-top:12px;font-size:12px;color:#4a7a9b">&#128202; ${ai.market_context}</p>` : ''}
  ${ai.watchlist ? `<div style="margin-top:16px;padding:14px 16px;border-radius:6px;background:rgba(61,155,233,0.07);border-left:3px solid #3d9be9"><div style="font-family:'Space Mono',monospace;font-size:9px;letter-spacing:0.13em;color:#3d9be9;text-transform:uppercase;margin-bottom:8px">&#128270; Watchlist — Potential Adds</div><p style="font-size:12px;color:#7a9ab5;line-height:1.7">${ai.watchlist}</p></div>` : ''}
