const d = $input.first().json;

// ── Day-based focus rotation ──────────────────────────────────
const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const dayName = days[new Date().getDay()];
const focusMap = {
  'Monday':    'Focus angle: Week ahead outlook — what needs action or monitoring this week.',
  'Tuesday':   'Focus angle: Individual position fundamentals — sector trends and holding quality.',
  'Wednesday': 'Focus angle: Risk assessment — what could go wrong, what needs protecting.',
  'Thursday':  'Focus angle: Dividend and income health — yield, payout dates, income sustainability.',
  'Friday':    'Focus angle: Week recap — what moved, why, and what to watch next week.',
  'Saturday':  'Focus angle: Portfolio rebalancing — anything to trim, add, or swap.',
  'Sunday':    'Focus angle: Macro and market context — rates, USD, PSE sentiment, crypto outlook.'
};

// ── Randomised analysis lens ──────────────────────────────────
const lenses = [
  'Write from a risk management perspective — highlight threats and downside scenarios.',
  'Write from an income investor perspective — prioritise yield, dividends, and cash flow.',
  'Write from a growth perspective — which positions have the most upside potential.',
  'Write from a capital preservation perspective — what needs protecting and why.',
  'Write from a sector rotation perspective — where is money flowing in SG and PH markets.'
];
const todayLens = lenses[new Date().getDate() % lenses.length];
const todayFocus = focusMap[dayName] || '';

// ── WoW strings ───────────────────────────────────────────────
const wowStr = d.sg_wow !== null
  ? (d.sg_wow >= 0 ? '+S$' : '-S$') + Math.abs(Math.round(d.sg_wow)) + ' vs last week'
  : 'no prior snapshot';
const peraWowStr = d.pera_wow !== null
  ? (d.pera_wow >= 0 ? '+₱' : '-₱') + Math.abs(Math.round(d.pera_wow)) + ' vs last week'
  : 'no prior snapshot';

const divStr = d.dividends && d.dividends.length
  ? '\nDividends Calendar:\n' + d.dividends.map(r =>
      `${r.n}: Ex-Date ${r.exDate}, Amount ${r.currency === 'SGD' ? 'S$' : '₱'}${r.amount.toFixed(4)}, Pay-Date ${r.payDate}`
    ).join('\n')
  : '';

const content = 'Return ONLY raw JSON, no markdown, no backticks. ' +
  'Portfolio as of ' + d.timestamp + '. ' +
  'Today is ' + dayName + '. ' + todayFocus + ' ' +
  'Analysis lens: ' + todayLens + ' ' +
  'MooMoo SG Total: S$' + d.total_value + ' PL: S$' + d.total_pl + ' (' + wowStr + '). ' +
  'DragonFi PERA+ Total: PHP ' + d.pera_total_val + ' PL: PHP ' + d.pera_total_pl + ' (' + peraWowStr + '). ' +
  'USDSGD: ' + d.usdsgd + ' PHPSGD: ' + d.phpsgd + divStr + ' ETH: S$' + d.eth_sgd + '. ' +
  'Alerts: ' + (d.alerts.length ? d.alerts.join(', ') : 'None') + '. ' +
  'MooMoo SG Positions: ' + d.rows.map(r => r.n + ' ' + (r.pct >= 0 ? '+' : '') + r.pct.toFixed(1) + '% S$' + Math.round(r.val)).join(', ') + '. ' +
  'DragonFi PERA+ Positions: ' + d.peraRows.map(r => r.n + ' ' + (r.pct >= 0 ? '+' : '') + r.pct.toFixed(1) + '% PHP' + Math.round(r.val)).join(', ') + '. ' +
  'Context: Bobby is a Singapore-based OFW investor. ' +
  'MooMoo SG: AJBU (Keppel DC Reit), A17U (CapLand Ascendas industrial/DC REIT), BUOU (Frasers Logistics REIT), J69U (suburban retail REIT), JYEU (Lendlease commercial REIT), ME8U (Mapletree Industrial Trust), O5RU (AIMS APAC industrial REIT), NVDA (tech growth), TSLA (growth), ETH (crypto growth/non-yielding). ' +
  'DragonFi PERA+: AREIT (Ayala Land REIT), CREIT (Citicore renewable energy), MBT (Metrobank), MREIT (Megaworld REIT), RCR (RL Commercial REIT). ' +
  'Strategy Context: Portfolio has a bimodal strategy: REITs & Banks (A17U, AJBU, BUOU, J69U, JYEU, ME8U, O5RU, AREIT, CREIT, MREIT, RCR, MBT) are long-term yield assets held for compound distributions — focus on dividend health, gearing, and distribution stability, and do NOT recommend panic-selling them on short-term price drops. US Equities (NVDA, TSLA) and Crypto (ETH) are tactical growth assets — recommend active capital protection triggers (stop-losses) or exit strategies here. ' +
  'Actionability constraint: Never give vague advice like "reassess positions". Always specify exact price-based actions or rebalancing ratios (e.g. "If ETH drops below S$2000, rotate into AJBU"). ' +
  'Return this JSON: {' +
  '"overall_summary":"2 to 3 sentences max. One line on SG portfolio health, one line on PERA+ health, one line on overall sentiment. Keep it punchy and fresh — do not repeat yesterday.",' +
  '"detailed_analysis":"4 to 5 sentences. Apply the focus angle and analysis lens above. Cover only notable movers and positions needing attention. Skip flat or unchanged positions. Be direct and specific — vary the angle from a typical daily recap.",' +
  '"watchlist":"2 sentences. One specific stock or REIT Bobby does not hold. Include ticker, exchange, and one reason why it fits today\'s analysis lens.",' +
  '"portfolio_status":"UP or DOWN or FLAT",' +
  '"biggest_mover":{"name":"","direction":"UP or DOWN","note":"one line"},' +
  '"positions":[{"name":"","pct":0.0,"status":"STRONG or OK or WATCH or ALERT","commentary":"max 10 words"}],' +
  '"pera_positions":[{"name":"","pct":0.0,"status":"STRONG or OK or WATCH or ALERT","commentary":"max 10 words"}],' +
  '"alerts":[{"level":"RED or YELLOW or GREEN","title":"","body":"1 sentence only"}],' +
  '"recommendation":"2 to 3 sentences. Apply the focus angle above. Most urgent action first. Be direct — what to do today or this week.",' +
  '"market_context":"1 sentence covering the most relevant macro factor right now aligned to today\'s focus angle."}';

return [{ json: { 
  ...d,
  claudeContent: content,
  claudeRole: 'user'
} }];

const d = $input.first().json;

const workflowStaticData = $getWorkflowStaticData('global');

workflowStaticData.latestSnapshot = {
  saved_at:       new Date().toISOString(),
  total_value:    d.total_value,
  total_pl:       d.total_pl,
  pera_total_val: d.pera_total_val,
  pera_total_pl:  d.pera_total_pl,
  usdsgd:         d.usdsgd,
  phpsgd:         d.phpsgd,
  eth_sgd:        d.eth_sgd,
  rows:           d.rows.map(r => ({ n:r.n, val:r.val, pl:r.pl, pct:r.pct })),
  peraRows:       d.peraRows.map(r => ({ n:r.n, val:r.val, pl:r.pl, pct:r.pct }))
};

return [{ json: d }];

const https = require('https');

const fallbackDividends = [
  { symbol: 'A17U.SI', n: 'A17U', exDate: '2026-03-31', amount: 0.0375, currency: 'SGD', payDate: '2026-04-30' },
  { symbol: 'AJBU.SI', n: 'AJBU', exDate: '2026-02-06', amount: 0.05248, currency: 'SGD', payDate: '2026-03-19' },
  { symbol: 'BUOU.SI', n: 'BUOU', exDate: '2026-05-14', amount: 0.0295, currency: 'SGD', payDate: '2026-06-22' },
  { symbol: 'J69U.SI', n: 'J69U', exDate: '2026-05-04', amount: 0.06136, currency: 'SGD', payDate: '2026-05-29' },
  { symbol: 'JYEU.SI', n: 'JYEU', exDate: '2026-02-24', amount: 0.005195, currency: 'SGD', payDate: '2026-03-30' },
  { symbol: 'ME8U.SI', n: 'ME8U', exDate: '2026-05-06', amount: 0.0309, currency: 'SGD', payDate: '2026-06-12' },
  { symbol: 'O5RU.SI', n: 'O5RU', exDate: '2026-05-15', amount: 0.026, currency: 'SGD', payDate: '2026-06-29' },
  { symbol: 'AREIT',    n: 'AREIT', exDate: '2026-05-26', amount: 0.62, currency: 'PHP', payDate: '2026-06-11' },
  { symbol: 'CREIT',    n: 'CREIT', exDate: '2026-06-10', amount: 0.049, currency: 'PHP', payDate: '2026-07-08' },
  { symbol: 'MBT',      n: 'MBT',   exDate: '2026-03-06', amount: 3.50, currency: 'PHP', payDate: '2026-03-26' },
  { symbol: 'MREIT',    n: 'MREIT', exDate: '2026-05-14', amount: 0.263, currency: 'PHP', payDate: '2026-05-29' },
  { symbol: 'RCR',      n: 'RCR',   exDate: '2026-05-18', amount: 0.1115, currency: 'PHP', payDate: '2026-06-01' }
];

function fetchChart(symbol) {
  return new Promise((resolve) => {
    const url = `https://query1.finance.yahoo.com/v8/finance/chart/${symbol}?interval=1d&range=6mo&events=div`;
    const options = {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
      },
      timeout: 5000
    };
    https.get(url, options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          resolve(JSON.parse(data));
        } catch(e) {
          resolve(null);
        }
      });
    }).on('error', () => resolve(null));
  });
}

const sleep = ms => new Promise(r => setTimeout(r, ms));

const liveDividends = [];
const sgxSymbols = ['A17U.SI', 'AJBU.SI', 'BUOU.SI', 'J69U.SI', 'JYEU.SI', 'ME8U.SI', 'O5RU.SI'];

for (const sym of sgxSymbols) {
  try {
    const data = await fetchChart(sym);
    await sleep(200);
    if (data && data.chart && data.chart.result && data.chart.result[0]) {
      const result = data.chart.result[0];
      const divEvents = result.events?.dividends;
      if (divEvents) {
        const timestamps = Object.keys(divEvents).map(Number).sort((a,b) => b - a);
        if (timestamps.length > 0) {
          const latestTs = timestamps[0];
          const event = divEvents[latestTs];
          const exDateObj = new Date(latestTs * 1000);
          const exDateStr = exDateObj.toISOString().split('T')[0];

          // Estimate payment date as ex-date + 33 days
          const payDateObj = new Date(exDateObj.getTime() + 33 * 24 * 60 * 60 * 1000);
          const payDateStr = payDateObj.toISOString().split('T')[0];

          liveDividends.push({
            symbol: sym,
            n: sym.split('.')[0],
            exDate: exDateStr,
            amount: event.amount,
            currency: 'SGD',
            payDate: payDateStr
          });
        }
      }
    }
  } catch(e) {
    // Keep processing other tickers
  }
}

const finalDividends = [];
for (const fb of fallbackDividends) {
  const live = liveDividends.find(l => l.n === fb.n);
  if (live) {
    finalDividends.push(live);
  } else {
    finalDividends.push(fb);
  }
}

// Sort dividends by ex-date descending
finalDividends.sort((a, b) => b.exDate.localeCompare(a.exDate));

const d = $input.first().json;
return [{ json: { ...d, dividends: finalDividends } }];

const allInputs = $input.all();

const yfInput = allInputs.find(i => 
  i.json.quoteResponse || 
  i.json.meta?.status === 200 ||
  Array.isArray(i.json.body)
) || allInputs[0];

const ethInput = allInputs.find(i => 
  i.json.body?.ethereum || 
  i.json.ethereum
) || allInputs[1];

const yfRaw = yfInput.json;
const quotes = yfRaw.quoteResponse?.result
             || yfRaw.body
             || (Array.isArray(yfRaw) ? yfRaw : []);
const yf = {};
quotes.forEach(q => {
  const sym = q.symbol || q.ticker || '';
  const price = q.regularMarketPrice?.raw ?? q.regularMarketPrice ?? 0;
  if (sym) yf[sym] = Number(price) || 0;
});

const usdsgd = yf['USDSGD=X'] || 1.35;
const phpsgd = yf['PHPSGD=X'] || 0.023;
const S = v => (v == null || isNaN(v) || !isFinite(v)) ? 0 : Number(v);

// ── Read ETH & PSE Prices from TradingView nodes ────────────────
let ethSGD = 0;
const tvPsePrices = {};

try {
  const tvEthData = $('TradingView ETHSGD').first().json;
  ethSGD = S(tvEthData.data?.[0]?.d?.[1]);
} catch (e) {
  // Fallback to CoinGecko input if TradingView fails
  const ethRaw = ethInput.json.body || ethInput.json;
  ethSGD = Number(ethRaw?.ethereum?.sgd) || Number(ethInput.json?.ethereum?.sgd) || Number(ethInput.json?.body?.ethereum?.sgd) || 0;
}

try {
  const tvPseData = $('TradingView PSE').first().json;
  (tvPseData.data || []).forEach(item => {
    const name = item.d[0];
    const close = item.d[1];
    tvPsePrices[name] = S(close);
  });
} catch (e) {
  // Handled via fallback values in the loop below
}

// ── SG + US Positions (C38U removed, names & costs matched to MooMoo console) ──
const pos = [
  {sym:'A17U.SI', n:'A17U',  qty:400,    cost:2.53,    c:'SGD'},
  {sym:'AJBU.SI', n:'AJBU',  qty:500,    cost:1.9562,  c:'SGD'}, // Name matched
  {sym:'BUOU.SI', n:'BUOU',  qty:1500,   cost:0.9398,  c:'SGD'}, // Cost updated
  {sym:'J69U.SI', n:'J69U',  qty:1000,   cost:2.1109,  c:'SGD'}, // Name matched, cost 2.1109
  {sym:'JYEU.SI', n:'JYEU',  qty:900,    cost:0.5898,  c:'SGD'},
  {sym:'ME8U.SI', n:'ME8U',  qty:200,    cost:1.93,    c:'SGD'},
  {sym:'NVDA',    n:'NVDA',  qty:3,      cost:173.73,  c:'USD'}, // Cost updated
  {sym:'O5RU.SI', n:'O5RU',  qty:500,    cost:1.2515,  c:'SGD'}, // Name matched, cost updated
  {sym:'TSLA',    n:'TSLA',  qty:0.3549, cost:318.683, c:'USD'}
];

let totVal = 0, totPL = 0;
const rows = [];

for (const p of pos) {
  const rawP = S(yf[p.sym]);
  const pr   = S(p.c === 'USD' ? rawP * usdsgd : rawP);
  const co   = S(p.c === 'USD' ? p.cost * usdsgd : p.cost);
  const val  = S(p.qty * pr);
  const cst  = S(p.qty * co);
  const pl   = S(val - cst);
  const pct  = cst > 0 ? S(pl / cst * 100) : 0;
  totVal += val; totPL += pl;
  rows.push({ n:p.n, price:rawP, currency:p.c, qty:p.qty, cost:p.cost, val, pl, pct, noP:!rawP });
}

// ── ETH (Blended cost and qty updated, row push corrected) ──────
const ethQty = 0.6338458;
const ethBlendedCost = 2526.13484;

const eV = S(ethQty * ethSGD);
const ePL = S(eV - ethQty * ethBlendedCost);
const ePct = S((ethSGD - ethBlendedCost) / ethBlendedCost * 100);

totVal += eV;
totPL  += ePL;

rows.push({ n:'ETH', price:ethSGD, currency:'SGD', qty:ethQty, cost:ethBlendedCost, val:eV, pl:ePL, pct:ePct, noP:false });

// ── DragonFi PERA+ Positions (Dynamic TV Prices & Fallback) ───
const peraFallback = {
  'AREIT': 38.40,
  'CREIT': 3.50,
  'MBT':   63.00,
  'MREIT': 14.00,
  'RCR':   6.75
};

const peraPos = [
  {n:'AREIT', qty:1200, cost:40.6445},
  {n:'CREIT', qty:8000, cost:3.4038},
  {n:'MBT',   qty:430,  cost:67.6711},
  {n:'MREIT', qty:1900, cost:13.5704},
  {n:'RCR',   qty:4300, cost:6.79}
];

let peraTotVal = 0, peraTotPL = 0;
const peraRows = [];

for (const p of peraPos) {
  const pricePhp = tvPsePrices[p.n] || peraFallback[p.n] || 0;
  const val      = S(p.qty * pricePhp);
  const cst      = S(p.qty * p.cost);
  const pl       = S(val - cst);
  const pct      = cst > 0 ? S(pl / cst * 100) : 0;
  peraTotVal += val;
  peraTotPL  += pl;
  peraRows.push({ n:p.n, sym:p.n + '.PS', price:pricePhp, qty:p.qty, cost:p.cost, val, pl, pct, noP:false });
}

// ── Alerts ─────────────────────────────────────────────────────
const alerts = [];
rows.forEach(r => {
  if (r.pct <= -10 && !r.noP && !r.stable) alerts.push(r.n + ' ' + r.pct.toFixed(1) + '%');
});
peraRows.forEach(r => {
  if (r.pct <= -10 && !r.noP) alerts.push('PERA+ ' + r.n + ' ' + r.pct.toFixed(1) + '%');
});

return [{ json: {
  rows,
  peraRows,
  total_value:    Math.round(totVal * 100) / 100,
  total_pl:       Math.round(totPL * 100) / 100,
  pera_total_val: Math.round(peraTotVal * 100) / 100,
  pera_total_pl:  Math.round(peraTotPL * 100) / 100,
  usdsgd,
  phpsgd,
  eth_sgd:        ethSGD,
  alerts,
  alert_count:    alerts.length,
  timestamp:      new Date().toISOString()
}}];

const calcPL = $('Calculate Dividends').first().json;
const rawResp = $input.first().json;

// ── Parse Claude response ──────────────────────────────────────
let ai;
try {
  const text = rawResp.choices[0].message.content;
  const clean = text.replace(/```json|```/g, '').trim();
  ai = JSON.parse(clean);
} catch(e) {
  ai = {
    overall_summary: 'Portfolio update complete. AI analysis unavailable this run.',
    detailed_analysis: '',
    watchlist: '',
    portfolio_status: calcPL.total_pl >= 0 ? 'UP' : 'DOWN',
    biggest_mover: { name: 'N/A', direction: 'UP', note: '' },
    positions: calcPL.rows.map(r => ({
      name: r.n, pct: r.pct,
      status: r.stable ? 'OK' : r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT',
      commentary: ''
    })),
    pera_positions: calcPL.peraRows.map(r => ({
      name: r.n, pct: r.pct,
      status: r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT',
      commentary: ''
    })),
    alerts: calcPL.alerts.length ? [{ level: 'YELLOW', title: 'Alerts', body: calcPL.alerts.join(', ') }] : [],
    recommendation: 'Review positions manually.',
    market_context: ''
  };
}

// ── Helpers ────────────────────────────────────────────────────
const ts = new Date(calcPL.timestamp).toLocaleString('en-SG', {
  timeZone: 'Asia/Singapore', weekday:'long', day:'2-digit',
  month:'short', year:'numeric', hour:'2-digit', minute:'2-digit'
});
const fmt    = v => (v >= 0 ? '+' : '') + 'S$' + Math.abs(Math.round(v)).toLocaleString();
const fmtPhp = v => (v >= 0 ? '+' : '-') + '₱' + Math.abs(Math.round(v)).toLocaleString();
const f1  = v => Number(v).toFixed(1);
const plColor    = v => v >= 0 ? '#00c896' : '#e74c3c';
const statusColor = s => ({ STRONG:'#00c896', OK:'#6db8a0', WATCH:'#f5a623', ALERT:'#e74c3c' }[s] || '#6db8a0');
const alertBg    = l => ({ RED:'rgba(231,76,60,0.12)', YELLOW:'rgba(245,166,35,0.10)', GREEN:'rgba(0,200,150,0.10)' }[l] || 'rgba(255,255,255,0.04)');
const alertBorder = l => ({ RED:'#e74c3c', YELLOW:'#f5a623', GREEN:'#00c896' }[l] || '#444');
const alertIcon  = l => ({ RED:'&#9940;', YELLOW:'&#9888;', GREEN:'&#9989;' }[l] || '&#8226;');

// ── MooMoo SG Position rows ────────────────────────────────────
const posRows = calcPL.rows.map(r => {
  const aiPos  = (ai.positions || []).find(p => p.name === r.n) || {};
  const status = r.stable ? 'OK' : r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT';
  const color  = statusColor(aiPos.status || status);
  const sign   = r.pct >= 0 ? '+' : '';
  const valStr = 'S$' + Math.round(r.val).toLocaleString();
  const plStr  = Math.abs(r.pl) < 1
    ? (r.pl >= 0 ? '+S$<1' : '-S$<1')
    : (r.pl >= 0 ? '+S$' : '-S$') + Math.abs(Math.round(r.pl)).toLocaleString();
  const plSGD  = r.pl >= 0 ? '#00c896' : '#e74c3c';
  return `<tr>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:#c8d8e8;padding:13px 12px">${r.n}</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:${color};padding:13px 8px">${sign}${r.pct.toFixed(1)}%</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:12px;color:${plSGD};padding:13px 8px">${plStr}</td>
    <td style="padding:13px 8px"><span style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.08em;padding:3px 9px;border-radius:20px;background:${color}22;color:${color};border:1px solid ${color}44">${aiPos.status || status}</span></td>
    <td style="font-size:11px;color:#6b8599;padding:13px 8px">${valStr}</td>
    <td style="font-size:12px;color:#7a9ab5;padding:13px 12px">${aiPos.commentary || ''}</td>
  </tr>`;
}).join('');

// ── DragonFi PERA+ rows ────────────────────────────────────────
const peraRows = calcPL.peraRows.map(r => {
  const aiPos  = (ai.pera_positions || []).find(p => p.name === r.n) || {};
  const status = r.pct >= 5 ? 'STRONG' : r.pct >= 0 ? 'OK' : r.pct >= -10 ? 'WATCH' : 'ALERT';
